('1b2eeb4f-4b9d-4344-a86b-946631b53022','C.Viper','Jump HP','','8HP','normal',11,5,NULL,6,11,800,'M','','Spikes down airborne opponents on hit; Forces stand on hit; Strong hitbox priority for vertical approaches; Projectile invincible on lower body (legs) on frames 11-23',15,datetime('now'),datetime('now')),
('106e1eb7-8dc0-484c-b973-c95dd9e5ac74','C.Viper','Jump LK','','8LK','normal',5,7,NULL,0,3,300,'M','','Can be used as a fuzzy instant Overhead; Combos naturally from any close-range Super Jump canceled normal against Standing tall characters (JP, Marisa, Sagat, Zangief); Very strong hitbox priority',16,datetime('now'),datetime('now')),
('b6dec052-910a-4520-be2e-b71cb1ce3ab7','C.Viper','Jump MK','','8MK','normal',7,6,NULL,3,7,500,'M','','Cross-up; Great all-purpose jump-in (C. Viper''s longest range forward jump normal) with exceptional hitbox priority; Projectile invincible on lower body (legs) on frames 7-20',17,datetime('now'),datetime('now')),
('35c9e3ca-4bd1-4524-8488-06cc5b8a662d','C.Viper','Jump HK','','7 or 9HK','normal',8,7,NULL,6,11,700,'M','sp','Cross-up; Cancelable into Air Burn Kick until the 37th airborne frame of jump or super jump (does not work in safe jump setups or on crouching opponents); Projectile invincible on lower body (legs) on frames 8-19',18,datetime('now'),datetime('now'));
