('7a0bbaa6-bc85-4f4e-ac07-64b30b379f56','Chun-Li','LK Hundred Lightning Kicks','','236LK','special',5,2,20,-8,3,800,'H','su3','3 hits; Carries over Counter-Hit bonus frame advantage to all hits; Puts airborne opponents into a limited juggle state on hit; Puts grounded opponents into a free juggle state knockdown on Punish Counter (can follow-up with a jab air reset pressure in the corner); Very fast start-up and good range makes this a great punish tool for things otherwise not in range of Chun-Li''s light attacks',47,datetime('now'),datetime('now')),
('3ec82a8f-3881-45c4-b58f-d2e8dfbb2c6c','Chun-Li','MK Hundred Lightning Kicks','','236MK','special',12,2,22,-8,3,900,'H','su3','4 hits; Carries over Counter-Hit / Punish Counter bonus frame advantage to all hits; Puts airborne opponents into a limited juggle state on hit',48,datetime('now'),datetime('now')),
