('bb062cad-be85-4d35-be1b-2faf4abbb2b6','Chun-Li','OD Spinning Bird Kick','','28KK','special',16,2,8,-12,NULL,800,'H','','Takes 30 frames to charge; Airborne on frames 14-63 (Forced Knockdown state); Launches grounded opponent into a limited juggle state on hit; Knocks down airborne opponents; Does not require charge if canceled into from Stance moves',59,datetime('now'),datetime('now')),
('19b5db53-26aa-473c-ab0b-56114494bd29','Chun-Li','LK Hazanshu','','214LK','special',23,2,21,-9,0,1000,'M','su3','Overhead; Lower half of body is Projectile invincible on frames 7-18; Airborne on frames 5-20 (Forced Knockdown state); Crouching state during recovery frames; Incurs a 20% damage scaling penalty if used as the first hit of a combo',60,datetime('now'),datetime('now')),
('dded3087-8b56-4d73-8600-ca91811d91d3','Chun-Li','MK Hazanshu','','214MK','special',27,3,16,-3,2,1000,'M','su3','Overhead; Lower half of body is Projectile invincible on frames 7-21; Airborne on frame 6-24 (Forced Knockdown state); Crouching state during recovery frames; Incurs a 30% damage scaling penalty if used as the first hit of a combo',61,datetime('now'),datetime('now')),
('ce89e7c5-e7f9-4f9f-8156-48da646bf31a','Chun-Li','HK Hazanshu','','214HK','special',32,3,16,-1,6,1200,'M','su3','Overhead; Lower half of body is Projectile invincible on frames 7-26; Airborne on frame 6-29 (Forced Knockdown state); +2F extra (18F) recovery frames on whiff; Crouching state during recovery frames; Incurs a 20% damage scaling penalty if used as the first hit of a combo',62,datetime('now'),datetime('now')),
('c031cd3d-55a4-483e-8827-24881dd6dfa3','Chun-Li','OD Hazanshu','','214KK','special',26,3,16,-5,NULL,1200,'M','su2, su3','Overhead; Lower half of body is Projectile invincible on frames 7-21 and then full body Projectile invincible on frames 22-28; Airborne on frame 6-23 (Forced Knockdown state); Launches opponent into an free juggle OTG state on hit; Crouching state during recovery frames; Incurs a 20% damage scaling penalty if used as the first hit of a combo; Counts as 2 hits of damage scaling when combo''d into',63,datetime('now'),datetime('now')),
('ce34c3d5-c537-4f23-9e7b-2579d84213fb','Chun-Li','LK Tenshokyaku','','22LK','special',5,3,27,-37,NULL,900,'H','','Invincible against airborne strikes on frames 1-10; Airborne on frames 8-45 (Forced Knockdown state); Cannot hit cross-up (behind Chun-Li); Chun-Li is in a crouching state during the final recovery frame',64,datetime('now'),datetime('now')),
('615a2b3c-8908-4237-a065-b5e6d3f32f7d','Chun-Li','MK Tenshokyaku','','22MK','special',7,3,31,-41,NULL,1000,'H','','Invincible against airborne strikes on frames 1-10; Airborne on frames 8-51 (Forced Knockdown state); Cannot hit cross-up (behind Chun-Li); Chun-Li is in a crouching state during the final recovery frame',65,datetime('now'),datetime('now')),
