INSERT INTO frame_data (id,character,move_name,move_name_jp,input,category,startup,active,recovery,on_block,on_hit,damage,guard,cancel_into,notes,sort_order,updated_at,created_at) VALUES
('43a35fb3-bc93-41be-8446-69a3f41b8ed9','Dee Jay','Jump HK','','8HK','normal',10,5,NULL,NULL,NULL,800,'M','','Decent jump-in that hits in front of Dee Jay before swinging his leg downward',18,datetime('now'),datetime('now')),
('4e5c4749-6fc8-418b-a15e-e9f064f9566c','Dee Jay','Knee Shot','','9 > 2LK','normal',6,NULL,3,2,5,300,'M','','Alters DJ''s trajectory causing him to fall slightly faster towards the ground, allowing DJ to manipulate his jump arcs and his pressure or setup options from a jump (up to 5F shorter airborne frames overall compared to a regular jump); Only possible during a forward jump; Active frames last until landing; Has a much larger hurtbox than regular jump-ins making this move easily get hit out of the air; Punish Counter state from active frame 2 and onward',19,datetime('now'),datetime('now')),
('e8bfab0e-6d35-4402-be22-6994905c0296','Dee Jay','Party in the Air','','8MP > 8HP','normal',8,7,NULL,NULL,NULL,1400,'M','','First hit (MP) puts airborne opponents into a limited juggle state and the second hit (HP) spikes down airborne opponents on hit',20,datetime('now'),datetime('now')),
('dd527117-3303-44db-ae2b-18852806d7eb','Dee Jay','Sunrise Heel','','6MK','normal',19,5,16,1,5,700,'H','su','Not an Overhead (despite looking like one); Plus on block normal with good range that combos naturally even from further away (even better combos when spaced out slightly); First 2 active frames cannot hit grounded opponents (only hits airborne); Doesn''t hit crouching opponents until active frame 4 which grants Dee Jay +1 extra frame advantage (+6 oH / +2 oB); Framedata listed in parentheses (X) refers to when used against crouching opponents; Strong oki / meaty tool; Spikes down airborne opponents on hit; First 3 active frames have very strong anti-air hitboxes (although extremely slow start-up for an anti-air); Cancelable into all Supers',21,datetime('now'),datetime('now')),
('195337d5-18c2-4c21-855e-e1a7ab9f87c7','Dee Jay','Face Breaker','','4HK','normal',7,2,20,-5,1,800,'H','sp, su','Head hurtbox is invincible to airborne strikes on frames 4-12; Forces stand (vital for his Jackknife Maximum combo routes); Good anti-air and combo tool that''s also fully cancelable; Cannot hit cross-up (behind Dee Jay); First hit puts airborne opponents into a juggle state on hit (second hit air resets them); Both hits put airborne opponents into a limited juggle state on Punish Counter; Carries over Counter-Hit / Punish Counter bonus frame advantage to both hits; Second hit still does 800 damage by itself it the first hit whiffs',22,datetime('now'),datetime('now')),
('0d8547ae-331a-4037-937b-8e5d84f5aea0','Dee Jay','Threebeat Combo 1','','5LP > 5MK','normal',9,3,20,-3,2,400,'H','','Solid poking tool from jab that''s easily hit confirmed into the third hit for the extra damage and +3 strike / throw mixup; Second hit (MK) can whiff on crouching from further away resulting in much worse frame advantage (-17 oH / -22 oB) listed in the parentheses; MK does not whiff if LP lands as a Punish Counter; 1-2F gap on block between hits; Incurs 20% damage scaling penalty if the prior LP was blocked',23,datetime('now'),datetime('now')),
('40aff5e8-bb76-4fc8-8418-ca872c8e67d5','Dee Jay','Threebeat Combo 2','','5LP > 5MK > 5MK','normal',14,3,19,-8,3,625,'H','','Good target combo to convert into damage and pressure from DJ''s stand LP; Leaves DJ with +3 on hit and in range for a strike / throw mixup',24,datetime('now'),datetime('now')),
('b8ab4a75-bcf6-483d-8cf7-2111d51879f8','Dee Jay','Funky Dance 1','','5MP > 5MP','normal',12,2,17,-2,2,500,'H','','The second hit can be delayed quite a bit which creates a frametrap on block for the opponent (cancel window is on frames 9-15 of MP); 2F extra recovery on BLOCK only; Puts airborne opponents into a free juggle state (and maintains current juggle state); Useful tool in Drive Rush juggles to carry opponent toward the corner',25,datetime('now'),datetime('now')),
('f9cffe9f-6723-4021-b2fe-e3e3c2bbd255','Dee Jay','Funky Dance 2','','5MP > 5MP > 5HP','normal',20,2,24,-8,NULL,1125,'H','','Last hit (HP) only combos if the second MP counter-hits (which can happen when the prior hits are delayed to create a frametrap scenario); Puts the opponent into a limited juggle state on hit; 3F gap on block between this HP hit and the prior MP for yet another frametrap setup',26,datetime('now'),datetime('now')),
('2bd3acd0-3541-49a8-a7ee-89b135e206a0','Dee Jay','Funky Dance Feint','','5MP > 5MP > 4HP','normal',NULL,NULL,22,-5,-3,500,'','','A feint option to keep the opponent guessing on if they want to try to challenge DJ''s MP Target Combo; Counter-Hit state for the entire feint duration',27,datetime('now'),datetime('now')),
('eeb4eb08-7a08-4fd6-9a8e-1ba1ab0d0c7c','Dee Jay','Dee Jay Special 1','','5MP > 5HP','normal',11,7,24,-11,-2,500,'H','','Can be spaced so the HP hits in later active frames for + frames on hit/block; Second hit (HP) can whiff on crouching from further away resulting in much worse frame advantage (-22 oH / -27 oB); Both hits always form a true blockstring; Puts airborne opponents into a free juggle state (and maintains current juggle state)',28,datetime('now'),datetime('now')),
('2880a54d-dc6c-410a-9d1a-6e6cbd66ba8c','Dee Jay','Dee Jay Special 2','','5MP > 5HP > 5HK','normal',13,3,30,-13,NULL,600,'H','su','Super cancelable; Puts opponent into a limited juggle state',29,datetime('now'),datetime('now')),
('7d6ff839-d6cb-4a49-a9f5-05411152cb42','Dee Jay','Speedy Maracas','','22PP','special',88,NULL,38,NULL,NULL,NULL,'','','Hold one punch button to continue dancing longer; Gains 1/5th of a bar of Super meter on frame 88 (frame 68 if starting with 2+ bars); Gains more Super meter (49 per frame; 10,000 is 1 bar) the longer Dee Jay dances; Takes 272 frames to build 1 bar of Super meter if Dee Jay continues dancing; Can be canceled into from any Air Slasher even on whiff; Dee Jay is in a Counter-Hit state for the entire duration (Punish Counter state if canceled into this from Air Slasher)',30,datetime('now'),datetime('now')),
('ffdc572b-0fae-4efb-8e64-ff23c60e3528','Dee Jay','Diss Track','','LPLK','throw',5,3,23,NULL,NULL,1200,'T','','Throw Loop: Dash up > whiff 5LP for +3 mixup between strike / throw (not possible on mid-screen back roll); Gets +70% damage increase (2040 damage), HKD (denies back-roll option on wake-up), and depletes 1 bar of Drive Gauge on a Punish Counter',31,datetime('now'),datetime('now')),
('2efb409b-2d01-4ec5-80c3-53079c355feb','Dee Jay','Flip Throw','','4LPLK','throw',5,3,23,NULL,NULL,1200,'T','','Back Throw oki when cornered: Can Drive Rush in for a strike/throw mix; Gets +70% damage increase (2040 damage), HKD (denies back-roll option on wake-up), and depletes 1 bar of Drive Gauge on a Punish Counter',32,datetime('now'),datetime('now')),
('809fe426-3f5e-460d-b9d7-c390cf948584','Dee Jay','Drive Impact: Wild Beat','','HPHK','unique',26,2,35,-3,NULL,800,'H','','2 hits of armor on frames 1-27; Damages opponents Drive Gauge on Block (1/2 bar) | Hit (1 bar) | Counter-Hit (1.25 bar) | Punish Counter (1.5 bar); Knocks down on hit; Crumples on Punish Counter or after absorbing at least 1 attack during start-up (+21 frames before the crumple state goes airborne, followed by airborne state on frames 22-46 before they are grounded) which counts as 2 hits of damage scaling; If the armor absorbs an attack it slows the overall start-up by 1F (27F total instead of 26F); Pushes the opponent far back on hit or block and causes a wall splat if they hit the wall; Wall Splat on block adds 20% damage penalty on the next hit; Wall splats on hit or during Burnout counts as 2 hits of damage scaling; Wall Splat puts opponent into a special juggle state where the next move juggles them even if it doesn''t normally (similar juggle rules as from Drive Rush); Does not cause wall splat if combo''d into from other moves or unblockable setups (Lock); Puts airborne opponents into a long spinning free juggle state when hit as a Punish Counter; Regular KDA without a Wall Splat: +35 KD; Corner wall splat on HIT: +65 KD | Block: +72 HKD; KDA can vary greatly depending on how high the opponent wall splats (higher KDA the higher they wall splat); Can clash with other Drive Impacts if they collide on the same active frame (start at exactly the same time); Costs 1 bar of Drive Gauge; The scrub killer',33,datetime('now'),datetime('now')),
('d8214b40-d120-451b-adb1-6d9da32ee0ae','Dee Jay','Drive Reversal: Leg Scratch','','6HPHK','unique',20,3,26,-6,NULL,500,'H','','Fully invincible on frames 1-22 (frames 1-20 when used on wake-up as a Reversal); Armor Break (blows through all armor like Drive Impact); Can be performed during blockstun or from a successful parry (trying to Drive Reversal after the blockstun is over will result in a Drive Impact); Can also be performed during wake-up as a Reversal, doing it this way speeds up the start-up frames by 2 frames (18F start-up instead of 20F); Drive Reversal immediately removes the current blockstun you''re in and starts the attack; Causes a 4F screen freeze that occurs after the 6th start-up frame, which can mess up the opponents input timing, or enable them to do a simple input OS to counter the Drive Reversal; Safe on block (-2) when used against an opponent currently in Burnout; Costs 2 bars of Drive Gauge',34,datetime('now'),datetime('now')),
('8afa3447-7443-482d-9580-eb062f3b79b6','Dee Jay','Drive Parry','','MPMK','unique',1,12,33,NULL,NULL,NULL,'','','Parries all strikes and projectiles (high and low) from frame 1; 12F parry window (can hold the parry to extend the parry window); Perfect Parry occurs on the first 2 active frames (cannot achieve Perfect Parry if you buffer into parry by holding it during Reversal windows; Perfect Parries have to be timed properly); Can still hold charge directions during Parry; Can block during the recovery frames of a regular parry (can still get hit during the recovery frames if you don''t block correctly); Getting thrown or hit at any point during the recovery frames of a whiffed parry attempt results in a Punish Counter; Successfully parrying a move puts you into the same amount of blockstun as that move would regularly do on block (but a Perfect Parry has only 1F of recovery); Throw invincible during the recovery of a successful parry (just like during blockstun); Perfect Parrying a strike has only 1F of recovery and disables the opponent from canceling their attack (basically a guaranteed punish opportunity); After a successful Perfect Parry, you suffer a 50% penalty to your Damage, Drive Gauge Generation, and Drive Gauge Damage on any of your following attacks when punishing the opponent (in addition, both you and the opponent suffer a 20% penalty to their Super Meter gain during this period); Fully invincible for 6F after a successful Perfect Parry against a strike, during which period you can cancel into anything you want and it carries over the brief invincibility frames; Perfect Parrying projectiles puts you into fixed 10 frames of recovery and applies the same 50% scaling penalties (and 20% Super Meter penalty) on your following attacks when punishing the opponent; Parrying a Strike and Projectile on the same frame will result in a regular parry for the strike attack (effectively ignoring the projectile''s hitstop / blockstun); Perfect Parrying a Strike and Projectile on the same frame will give a screen freeze like you Perfect Parried a Strike, but still give you 10F recovery as if you had Perfect Parried a Projectile; Can cancel into Drive Rush during active frames 3 and onward (fastest Drive Rush method is to buffer a forward input before doing parry + forward again); Can cancel into Drive Reversal from a successful parry (just like you can normally during blockstun); Costs 1/2 bar Drive Gauge (continues to deplete Drive Gauge as you hold the Parry); You lose the parry if you go into Burnout from the Drive Gauge cost; Rewards 1 bar Drive Gauge (1/2 bar total after factoring in the initial parry cost) for successfully parrying a strike; Rewards 1/2 bar of Drive Gauge (0 bar total after factoring in the initial parry cost) for successfully parrying a projectile; Rewards 2 bars of Drive Gauge (1.5 bars total after factoring in the initial parry cost) for successful parrying a Drive Impact; Successfully parrying a strike attack splits the regular block pushback between both players (while Perfect Parrying a strike removes all of its pushback); Successfully parrying a projectile or Drive Impact reduces the pushback of it by half (while Perfect Parrying a projectile or Drive Impact removes all of its pushback); Your hurtbox and throw box expand slightly towards the opponent for the entire duration of the Parry (Throw box extension starts instantly on frame 1, while the Hurtbox extension starts on frame 3, after the initial 2F Perfect Parry window); Parrying while crouching maintains a regular crouch hurtbox for the first 2 frames of the parry (during the initial Perfect Parry window)',35,datetime('now'),datetime('now')),
('ec59f41c-5519-4f99-baa8-00c2c2200cc5','Dee Jay','Drive Rush','','MPMK / 66 (cancel)','unique',9,45,24,NULL,NULL,NULL,'','','Dashes forward and enhances the next normal used out of the Drive Rush with +4 extra hitstun / blockstun (some moves also get unique properties enhanced such as juggle state); The +4 bonus frame advantage gained from a Drive Rush enhanced move also stacks with any bonus frame advantage that move may have gained from Counter-Hit or Punish Counter; Cancelable into from special cancelable grounded normals; Drive Rush maintains buffers (freezes the buffer window) during it start-up and freeze frames - This allows players to do things normally not possible within the normal buffer windows, such as Drive Rushing into a charge special; The initial freeze frames that occur when a Drive Rush happens eats the opponents inputs; Framedata shown in parentheses refers to the Drive Rush version used from a Parry; Drive Rush recovery frames is only 24F total (23F if done from a Parry) - but the enhanced dash itself is 46F total (45F if done from Parry) and you can cancel it as early as frame 9 (frame 11 if done from a Parry); You stop building any form of Drive Gauge on your attacks after using a Drive Rush in the MIDDLE of a combo (but you still continue to build drive gauge as normal if you did Drive Rush at the START of a combo); Applies extra damage scaling penalty after using a Drive Rush in the MIDDLE of a combo (no damage scaling if you use Drive Rush at the START of a combo); Costs 3 bars of Drive Gauge if canceled into from a move; Costs 1/2 bar of Drive Gauge if canceled into from Parry (for a total of 1 bar of Drive Gauge when you factor in the initial 1/2 bar cost of the Parry)',36,datetime('now'),datetime('now')),
('b0bcf64b-4dd9-4d83-ac02-ca64c1360f79','Dee Jay','Taunt','','5PPPKKK','unique',NULL,NULL,NULL,NULL,NULL,NULL,'','','',37,datetime('now'),datetime('now')),
('90e09d2a-7a64-40cd-830e-3be24514f8aa','Dee Jay','LP Air Slasher','','46LP','special',NULL,NULL,21,NULL,NULL,NULL,'','','Takes 45 frames to charge (holds charge for 10F after leaving charge); Can be useful to bait the opponent and also useful to extend blockstrings / combos and keep the opponent guessing',38,datetime('now'),datetime('now')),
('5bb0ab4b-3a79-4698-b795-f4779448021e','Dee Jay','MP Air Slasher','','46MP','special',17,NULL,27,-5,0,600,'H','su3','1-hit projectile; Projectile Speed: 0.03 (1-2F) -> 0.115 (3F~); Takes 45 frames to charge (holds charge for 10F after leaving charge); Can be canceled into Speedy Maracas after 23F even on whiff',39,datetime('now'),datetime('now')),
('ef69b01a-ea8c-4809-a530-5bc0dd0bda92','Dee Jay','HP Air Slasher','','46HP','special',17,NULL,26,-3,3,1000,'H','su3','Two separate 1-hit projectiles; Projectile Speed: 0.03 (1-2F) -> 0.115 (1st) / 0.155 (2nd) on 3F and onward (Second projectile travels slightly faster than the first; Takes 45 frames to charge (holds charge for 10F after leaving charge); Carries over Counter-Hit / Punish Counter bonus frame advantage to both projectiles; Can be canceled into Speedy Maracas after 35F even on whiff',40,datetime('now'),datetime('now')),
('7f756d9e-5337-4be6-bef9-5e73e70511b9','Dee Jay','OD Air Slasher','','46PP','special',10,11,23,2,5,1000,'H','su2, su3','Two separate 1-hit projectiles (combines into a 2-hit projectiles if the first projectiles doesn''t connect up close); Projectile Speed: 0.15 (starts moving forward on frame 22); Takes 45 frames to charge (holds charge for 10F after leaving charge); Carries over Counter-Hit / Punish Counter bonus frame advantage to both projectiles; Strong frame advantage as well as minimal pushback on hit or block makes this an excellent combo and pressure tool up close; The combined 2-hit projectile puts the opponent into a limited juggle state on hit (if the first projectiles connects up close it keeps the opponent grounded); Puts airborne opponents into a limited juggle state; Incurs 20% damage scaling penalty if used as the first hit of a combo',41,datetime('now'),datetime('now')),
('4ad7af5b-27d9-4147-842e-a08143c17227','Dee Jay','LK Jackknife Maximum','','28LK','special',23,NULL,6,NULL,NULL,NULL,'','','Takes 40 frames to charge (holds charge for 12F after leaving charge); Airborne on frame 6 until landing; Start-up frames listed (23F) refers to when DJ can start canceling his feint into air normals; 6F landing recovery on whiff (otherwise the normal 3F landing recovery if DJ does any move in the air); Effectively gives DJ access to an alternative jumping angle / trajectory',42,datetime('now'),datetime('now')),
('4b7b4794-fe34-4f70-8260-fb18b8c019da','Dee Jay','MK Jackknife Maximum','','28MK','special',6,4,22,-32,NULL,1100,'H','','Takes 40 frames to charge (holds charge for 12F after leaving charge); Invincible to airborne strikes on frames 1-5 (can trade with a jump-in during active frames); Throw invincible on frames 5-6; Airborne on frames 5-44; Cannot hit cross-up (behind Dee Jay); Whiffs on crouch in most situations; Puts opponent into a limited juggle state',43,datetime('now'),datetime('now')),
('5a32cdff-4957-46de-9f5d-ce4ce7031597','Dee Jay','HK Jackknife Maximum','','28HK','special',5,5,17,-44,NULL,1300,'H','','Takes 40 frames to charge (holds charge for 12F after leaving charge); Invincible to airborne strikes on frames 1-9; Throw invincible on frame 5; Airborne on frames 5-50; Cannot hit cross-up (behind Dee Jay); Whiffs on crouch in most situations; The first hit has extra range against airborne opponents only; KD +42 against grounded opponents gives Dee Jay a perfect safe jump setup (KD +37 if juggled after MK Jackknife Maximum against grounded opponents, which also gives a perfect safe jump setup with Knee Shot (down LK during fwd jump); Last hit ends any juggle state (+100 Juggle Increase) so use this as a combo ender',44,datetime('now'),datetime('now')),
('c2a6ecd6-fafe-4046-a8da-bb83eba79b03','Dee Jay','OD Jackknife Maximum','','28KK','special',6,6,29,-55,NULL,1500,'H','','Fully invincible on frames 1-11; Takes 40 frames to charge (holds charge for 12F after leaving charge); Only the first hit connects on crouching opponents; Puts opponent into a limited juggle state; Airborne on frames 5-62; Cannot hit cross-up (behind Dee Jay)',45,datetime('now'),datetime('now')),
('f14ad806-38dd-4ec3-9752-9798d5986f3a','Dee Jay','LK Double Rolling Sobat','','236LK','special',NULL,NULL,26,NULL,NULL,NULL,'','','Just so happens to be a great framekill and setup tool for a bunch of DJ''s setups and knockdown situations, making this not just a feint tool but also a part of DJ''s mixup game and kit as a whole',46,datetime('now'),datetime('now')),
('29d64ada-f557-4a0b-8b9d-7ef687ba7af0','Dee Jay','MK Double Rolling Sobat','','236MK','special',12,3,23,-6,NULL,1000,'H','su3','Fast start-up and solid range makes this a good combo and poke tool in neutral (can be spaced to be safe on block)',47,datetime('now'),datetime('now')),
('42c06f65-ef5e-47ba-b93f-6054aa3a9c41','Dee Jay','HK Double Rolling Sobat','','236HK','special',15,3,24,-10,2,1400,'H','su3','Keeps DJ close on hit for +2 mixup pressure; Decent start-up and far range makes this a good combo / whiff punish tool in neutral; Carries over Counter-Hit / Punish Counter bonus frame advantage to both hits; Only first hit is cancelable into super',48,datetime('now'),datetime('now')),
('5c65b171-aaa3-4e0b-ac56-3510f5027aa6','Dee Jay','OD Double Rolling Sobat','','236KK','special',19,2,19,-2,NULL,1300,'H','su2, su3','Low crushes on frames 14-28; Not actually airborne despite what it looks like; Puts the opponent into a limited juggle state (can be combo''d into level 2 and 3 Supers)',49,datetime('now'),datetime('now')),
('eab29e34-13f1-4b79-93ad-a6f663108f08','Dee Jay','LP Machine Gun Upper','','214LP','special',15,4,35,-19,NULL,1650,'H','su3','Mostly a combo / juggle tool; Only version that combos naturally from DJ''s crouch MP; Doesn''t play out the full hits if the opponent is hit too high in the air (but even so it''s still a decent tool in some juggle scenarios); Deals up to 950 damage against airborne opponents (only 800 if the first active frame whiffs); Puts opponent into a limited juggle state on hit; Cannot hit cross-up (behind Dee Jay)',50,datetime('now'),datetime('now')),
('e93698d5-8684-42f8-a16f-7f3f58dfcef4','Dee Jay','MP Machine Gun Upper','','214MP','special',22,4,35,-19,NULL,1900,'H','su3','Mostly a combo / juggle tool; Can combo naturally into this from stand HP; Doesn''t play out the full hits if the opponent is hit too high in the air (but even so it''s still a decent tool in some juggle scenarios); Deals up to 900 damage against airborne opponents (only 800 if the first active frame whiffs); Puts opponent into a limited juggle state on hit; Cannot hit cross-up (behind Dee Jay)',51,datetime('now'),datetime('now')),
('ebaa84e4-fdc3-4175-8afd-46ee6a7aa616','Dee Jay','HP Machine Gun Upper','','214HP','special',28,4,35,-19,NULL,2200,'H','su3','Mostly a combo / juggle tool; Only comboable into during Punish scenarios or after utilizing Drive Rush; Doesn''t play out the full hits if the opponent is hit too high in the air (but even so it''s still a decent tool in some juggle scenarios); Deals up to 1900 damage against airborne opponents (only 800 if the first active frame whiffs); Puts opponent into a limited juggle state on hit (can link into SA3 after hitting airborne opponents for potentially huge damage); Cannot hit cross-up (behind Dee Jay)',52,datetime('now'),datetime('now')),
('6dfdf1b5-3636-487c-886a-8b6af53566a8','Dee Jay','OD Machine Gun Upper','','214PP','special',28,4,35,-19,NULL,2500,'H','su2, su3','Mostly a combo / juggle tool; Only comboable into during Punish scenarios or after utilizing Drive Rush; Doesn''t play out the full hits if the opponent is hit too high in the air (but even so it''s still a decent tool in some juggle scenarios); Deals only 800 damage against airborne if the first active frame whiffs; Cannot hit cross-up (behind Dee Jay)',53,datetime('now'),datetime('now')),
('6b628696-4448-4cd4-a35d-37841bd1d45b','Dee Jay','Jus Cool','','214K','special',13,NULL,24,NULL,NULL,NULL,'','','Follow-ups possible on frames 13-25; Follow-ups can be delayed quite a bit which gives DJ the time to react to the opponents actions as well as mix-up his own timings; Great shimmy tool with built-in mixups and whiff punishers to keep the opponent guessing on DJ''s approach; Because the attacking player suffers all the shared pushback of a move against a cornered opponent, it effectively makes DJ sway further back when canceled into normals against a cornered opponent',54,datetime('now'),datetime('now')),
('adb72878-9dd0-4595-9ed5-669d2b8bdda4','Dee Jay','Jus Cool > Funky Slicer','','214K > LK','special',13,3,22,-3,2,800,'L','su3','Low attack; Great whiff punish tool after baiting the opponent; Great pressure tool against opponents in Burnout (+1 on block and becomes a frametrap when canceled into from stand HP); 2F less recovery (20F) on block only; +3F extra recovery frames (25F) on whiff only; Incurs 20% damage scaling penalty if used as the first hit of a combo',55,datetime('now'),datetime('now')),
('3c136bb8-92a3-4d9b-930d-7a4e42a2b95f','Dee Jay','Jus Cool > Waning Moon','','214K > MK','special',13,3,16,1,NULL,1000,'M','','Overhead; Low crushes on start-up frames 12-22 of the Overhead follow-up; Causes a HKD on hit for follow-up mixups, while also being +1 on block allowing for continued pressure; Causes a limited OTG juggle state on Punish Counter; +1 extra KDA (+28 HKD) on crouching opponents; Causes a spiked Hard Knockdown on airborne opponents (slightly lower KD advantage than normal)',56,datetime('now'),datetime('now')),
('0d8b78e4-8dc7-4307-b494-84425c34b768','Dee Jay','Jus Cool > Maximum Strike','','214K > HK','special',13,5,25,-10,NULL,1000,'H','su3','Upper body invincible on start-up frames 6-14 and again on frames 20-44 (entire recovery frames) of the follow-up kick; Upper body and the extended kicking leg are invincible to airborne strikes on frames 15-19 (during active frames); Has shorter range against crouching opponents; Launches the opponent into a limited juggle state; Can hit cross-up (behind Dee Jay)',57,datetime('now'),datetime('now')),
('9641693a-f2d0-4005-a0b6-286b6b37e266','Dee Jay','Jus Cool > Juggling Dash','','214K > 6P','special',13,NULL,27,-15,NULL,NULL,'','','Projectile invincible on frames 1-20 of the follow-up crouch dash (frames 14-33 overall); DJ dashes forward to quickly close the gap, ducking under any projectiles or high hitting attacks; This dash can further be canceled into another follow-up back dash on frames 18-23 (frames 31-36 overall)',58,datetime('now'),datetime('now')),
('1355af9d-91e8-4f41-9a7a-9ac1bf3aea08','Dee Jay','Jus Cool > Juggling Dash > Juggling Sway','','214K > 6P > 4P','special',13,NULL,29,-31,NULL,NULL,'','','DJ hops back again to bait the opponent (no projectile invincibility or crouch sized hurtboxes like the prior forward dash); Only 1F faster and slightly further distance covered than if DJ had just backdashed instead after the prior forwards dash',59,datetime('now'),datetime('now')),
('5a40ff8b-d7f4-4fe4-a4a3-53c57e785306','Dee Jay','OD Jus Cool','','214KK','special',8,5,36,-18,NULL,500,'H','','Launches the opponent into a limited juggle state; Follow-ups possible on frames 13-25 of the follow-up sway after the initial punch (frames 25-37 overall); Dash follow-up (6P) can be executed 6F earlier than the other follow-ups; +1F extra recovery frame (37F) on block; The attack follow-ups can be executed 3F earlier on block (allows for better frametrap / Burnout pressure opportunities); Follow-ups can be delayed quite a bit which gives DJ the time to react to the opponents actions as well as mix-up his own timings; Follow-ups can be executed 3F earlier on BLOCK only (this turns the LK follow-up into a true blockstring or frametrap tool depending on input timing); Great shimmy tool with built-in mixups and whiff punishers to keep the opponent guessing on DJ''s approach; Because the attacking player suffers all the shared pushback of a move against a cornered opponent, it effectively makes DJ sway further back when canceled into normals against a cornered opponent',60,datetime('now'),datetime('now')),
('a9028d1e-ef7e-4cd5-a057-556be044567d','Dee Jay','OD Jus Cool > Funky Slicer','','214KK > LK','special',25,3,19,-2,6,900,'L','su2, su3','Low attack; Great whiff punish tool after baiting the opponent; Can trade into heavy hitting combos against opponents mashing 4F jabs when canceled into from stand HP (this becomes a true blockstrings and +2 on block during Burnout); +5F extra recovery frames (24F) on whiff; Puts airborne opponents into a limited juggle state',61,datetime('now'),datetime('now')),
('fd9d6968-1297-4fb4-b875-2b848f9bf913','Dee Jay','OD Jus Cool > Waning Moon','','214KK > MK','special',25,5,17,-2,5,1110,'M','','Overhead; Low crushes on start-up frames 12-22 of the Overhead follow-up; Keeps the opponent grounded on hit for follow-up combos while also being completely safe on block; +5 oH / -4 oB against taller standing characters like Zangief / Marisa / JP; Hits late on all crouching opponents resulting in +6 oH; Puts airborne opponents into a limited OTG juggle state that can combo into OD Jackknife, MK/HK Sobat, or Supers (important combo tool to bypass the damage scaling of OD Maximum Strike); The juggle state is a lot more lenient if this hits airborne as a Punish Counter, allowing for all sorts of combo extensions',62,datetime('now'),datetime('now')),
('af4ce637-c3b6-4e32-bda6-03a1909c33db','Dee Jay','OD Jus Cool > Maximum Strike','','214KK > HK','special',25,5,21,-8,NULL,1000,'H','su2, su3','Upper body invincible on frames 6-36; Has shorter range against crouching opponents; Launches the opponent into a limited juggle state on hit / counter-hit; Launches the opponent higher into a free juggle state on Punish Counter (if the prior OD Jus Cool (qcb+KK) whiffs); The KDA (Knockdown Advantage) shown in parantheses refers to when this move juggles as a follow-up to the OD Jus Cool (qcb+KK) launcher; Can hit cross-up (behind Dee Jay); Counts as 2 hits of damage scaling when combo''d into',63,datetime('now'),datetime('now')),
('4f1b50e2-fa02-4afd-a047-a9135f6bec0e','Dee Jay','OD Jus Cool > Juggling Dash','','214KK > 6P','special',19,NULL,22,-15,NULL,NULL,'','','Projectile invincible on frames 1-17 of the follow-up crouch dash (frames 20-36 overall); DJ dashes forward to quickly close the gap, ducking under any projectiles or high hitting attacks; Can be canceled into another follow-up back dash on frames 18-23 (frames 31-36 overall); Can dash under the opponent for side-switching juggles',64,datetime('now'),datetime('now')),
('d0681562-5cbc-4095-ab43-d55f7c20d1e0','Dee Jay','OD Jus Cool > Juggling Dash > Juggling Sway','','214KK > 6P > 4P','special',19,NULL,22,-31,NULL,NULL,'','','DJ hops back again to bait the opponent (no projectile invincibility or crouch sized hurtboxes like the prior forward dash); Only 1F faster and slightly further distance covered than if DJ had just backdashed instead after the prior forwards dash',65,datetime('now'),datetime('now')),
('0509edae-202d-4387-b30c-99ae3abcb962','Dee Jay','The Greatest Sobat','','236236K','super',7,4,33,-12,NULL,2000,'H','','No invincibility whatsoever; Armor Break; Low crushes on frames 4-14; No hurtbox extension whatsoever (can force a trade against some projectiles for a follow-up combo); Very safe on block compared to other Supers (can be spaced out to be relatively safe even on block); Puts the opponent into a free juggle Crumple state on Counter Hit and Punish Counter allowing for follow-up juggles (grounded combo follow-ups can be possible if close enough; +4 before airborne on Counter Hit / +6 on Punish Counter); Cause a sliding Hard Knockdown on airborne opponents; Punish Counter vs. airborne opponents causes a wall bounce and free juggle state (opponent can fly over Dee Jay''s head if near the corner); Counter Hit crumple has less KDA (HKD +66) and fewer follow-up combo options; Depletes 0.5 Drive Bar on hit for the opponent',66,datetime('now'),datetime('now')),
('14053db2-e3c8-45db-8637-4c6a1cc98eb8','Dee Jay','Lowkey Sunrise Festival','','236236LP > LP > MP > HP > LK > MK > HK (bad)','super',12,5,46,-29,6,1200,'H','','Fully invincible on frames 1-16 (follow-ups are also projectile invincible); Armor Break; First hit forces stand (relevant for combo follow-ups); This LP version of the Level 2 Super is the easiest one to do the rhythm for but it also deals the least amount of damage and limited to a lesser HK finisher; Dee Jay is +6 on hit for the first 5 hits of this super, allowing for follow-up combos (last HK hit knocks down); Damage shown in parentheses (2600) refers to the full version if Dee Jay does the HK knockdown finisher; Depletes 0.5 Drive Bar on hit for the opponent; Can hit cross-up (behind Dee Jay); 30% penalty to Super meter gain on any of the follow-up hits Dee Jay combos into after this move',67,datetime('now'),datetime('now'));
