('802a6ca9-691b-45db-b6aa-37a5879cf4b4','Dee Jay','Marvelous Sunrise Festival','','236236MP > LP > MP > HP > LK > MK > HK (good)','super',12,5,46,-29,6,1300,'H','','Fully invincible on frames 1-16 (follow-ups are also projectile invincible); Armor Break; First hit forces stand (relevant for combo follow-ups); This MP version of the Level 2 Super is easier to do the rhythm for than the HP version, but it also deals 100 less damage (200 less damage overall if you do the HP / HK finishers); Each button pressed at the right beat deals an extra 100 damage; Dee Jay is +6 on hit after the first 5 hits (up to MK) allowing for follow-up combos; The final HK hit puts the opponent into a Crumple state which can only combo''d from with the HP / HK finishers; Depletes 0.5 Drive Bar on hit for the opponent; Can hit cross-up (behind Dee Jay); 30% penalty to Super meter gain on any of the follow-up hits Dee Jay combos into after this move',68,datetime('now'),datetime('now')),
('a2ff636d-6918-4dab-a34d-d9fd86bd9209','Dee Jay','Headliner Sunrise Festival','','236236HP > LP > MP > HP > LK > MK > HK (great)','super',12,5,46,-29,6,1300,'H','','Fully invincible on frames 1-16 (follow-ups are also projectile invincible); Armor Break; First hit forces stand (relevant for combo follow-ups); This HP version of the Level 2 Super is the hardest to do the rhythm for but also deals the most amount of damage; Each button pressed at the right beat deals an extra 100 damage; Dee Jay is +6 on hit after the first 5 hits (up to MK) allowing for follow-up combos; The final HK hit puts the opponent into a Crumple state which can only combo''d from with the HP / HK finishers; Depletes 1 Drive Bar on hit for the opponent; Can hit cross-up (behind Dee Jay); 30% penalty to Super meter gain on any of the follow-up hits Dee Jay combos into after this move',69,datetime('now'),datetime('now')),
('552366c7-bd03-45ab-ba21-815828ff0940','Dee Jay','Climactic Strike','','HP (after Level 2 Super (MP/HP) connects)','super',1,NULL,180,NULL,NULL,2800,'H','','Switches sides with the opponent and has less knockdown advantage than the HK finisher; 6F less KDA (HKD +18) against airborne opponents; Depletes 1 Drive Bar on hit for the opponent',70,datetime('now'),datetime('now')),
('3e809986-6d10-4d80-81a5-9626becfab93','Dee Jay','Encore Beat','','HK (after Level 2 Super (MP/HP) connects)','super',1,NULL,150,NULL,NULL,2800,'H','','Has increased knockdown advantage over the HP finisher; 3F more KDA (HKD +37) against airborne opponents; Depletes 1 Drive Bar on hit for the opponent',71,datetime('now'),datetime('now')),
('f62e3394-d130-4e2b-a5aa-3b91568b17aa','Dee Jay','Weekend Pleasure','','214214P','super',9,5,48,-28,NULL,4000,'H','','Fully invincible on frames 1-13; Armor Break; Depletes 1.5 bars on hit for the opponent; Super cinematic time regenerates ~2 Drive Bars for Dee Jay; Cannot hit cross-up (behind Dee Jay)',72,datetime('now'),datetime('now')),
('117af156-12f7-431a-918d-6a6d12872f62','Dee Jay','Weekend Pleasure (Critical Art)','','214214P (CA)','super',9,5,48,-28,NULL,4500,'H','','Fully invincible on frames 1-13; Armor Break; Critical Art does +500 extra damage over regular version; Depletes 2 bars on hit for the opponent; Super cinematic time regenerates ~2.3 Drive Bars for Dee Jay; Cannot hit cross-up (behind Dee Jay)',73,datetime('now'),datetime('now')),
