('1740e99c-ebc6-490f-beba-c332e985c9e2','Dhalsim','Yoga Mountain','','4HK','normal',14,6,20,-9,0,1000,'H','','Very slow anti-air; Low profiles on frames 10-13 and again on frames 33-38; Extended leg is air strike invincible on frames 14-27; Cannot hit cross-up (behind Dhalsim); Puts airborne opponents into limited juggle state on Counter-Hit / Punish Counter',29,datetime('now'),datetime('now')),
