('75a94b1b-c483-4987-b61f-c88d79805515','Ed','OD Psycho Uppercut','','623PP','special',13,6,36,-28,NULL,800,'H','','Fully invincible on frames 1-16 (gains extended invincibility on HIT for the follow-up swing); Cannot hit cross-up (behind Ed); Has +5F extra recovery frames (41F) on hit or block; Framedata listed refers to the version that plays out on whiff (performs an extra attack on hit or block); Slow start-up makes this a poor reversal on wake-up but can be used to blow through the opponents buttons / delayed tech / Reversals',42,datetime('now'),datetime('now')),
('4addc8cb-deac-4a4d-8ff2-5346cecde618','Ed','LP Psycho Blitz','','214LP','special',11,3,14,-5,3,800,'H','su3','3 hits; Carries over Counter-Hit / Punish Counter bonus frame advantage to all hits; Puts airborne opponents into a limited juggle state on hit',43,datetime('now'),datetime('now')),
('c17a31cd-4b85-489e-a410-868930d0da86','Ed','MP Psycho Blitz','','214MP','special',13,2,16,-12,NULL,900,'H','su3','3 hits; Puts the opponent into a limited juggle state on hit; +8 recovery frames (24F) on block only',44,datetime('now'),datetime('now')),
