('e1d69000-f16a-4129-919b-79a0f51972af','Jamie','Jump MP [D2]','','8MP','normal',7,4,NULL,NULL,NULL,700,'M','sp','Puts airborne opponents into a juggle state; Cancelable into his Divekick (Drink Level 1) during forward jump; Shifts the normal jumping hurtbox upward during start-up (helps with avoiding some attacks); Juggle Limit / Increase / Start: 2 / 1 / 1',147,datetime('now'),datetime('now')),
('a7acda59-2881-48ca-be5c-6d919b3d5e6a','Jamie','Jump HP [D2]','','8HP','normal',10,6,NULL,NULL,NULL,800,'M','','Spikes down airborne opponents; Has some natural juggle limit (similar to jump MP); I whip my hair back and forth!',148,datetime('now'),datetime('now')),
