('6751f865-a2e5-4dde-9a37-aa1c155b858b','Juri','Sakkai Fuhazan (0 stock)','','236236K','super',7,43,58,-32,NULL,1800,'H','','Strike and Throw invincible on frames 1-8; Has a large trailing hurtbox immediately after super freeze to prevent fireball evasion; Super projectile hitboxes; Projectile speed: 0.12 (final hit: 0.22); Higher KDA the further away from the wall the opponent is (+26 KD when hitting a cornered opponent for example); Armor Break; Depletes 0.5 Drive Bar on hit for the opponent',55,datetime('now'),datetime('now')),
('3c9c3d17-9152-4f97-a12f-bc3973d66601','Juri','Sakkai Fuhazan (1 stock)','','236236K (hold)','super',7,43,58,-32,NULL,2100,'H','','Strike and Throw invincible on frames 1-8; Has a large trailing hurtbox immediately after super freeze to prevent fireball evasion; Super projectile hitboxes; Projectile speed: 0.12 (final hit: 0.22); Higher KDA the further away from the wall the opponent is (+26 KD when hitting a cornered opponent for example); Hold down the kick button during the Super to do this version (costs 1 Fuha stock); +300 bonus damage over regular version; Armor Break; Depletes 0.5 Drive Bar on hit for the opponent',56,datetime('now'),datetime('now'));
INSERT INTO frame_data (id,character,move_name,move_name_jp,input,category,startup,active,recovery,on_block,on_hit,damage,guard,cancel_into,notes,sort_order,updated_at,created_at) VALUES
('50776a2c-946f-4425-865a-d49fa4cda7d7','Juri','Feng Shui Engine','','214214P','super',1,NULL,6,NULL,NULL,NULL,'','','Duration of 600 frames (10 seconds) - The remaining timer freezes during any hitstop; Allows Juri to cancel all her normals into subsequent normals of equal or higher strength; Alters the properties of all the Heavy normals and f+MK Overhead when they are chained into (see the Super Install page framedata and notes on said moves for that information); Allows Juri to cancel from normals that she couldn''t cancel from before (stand HK / crouch LK / crouch HK / f+MK Overhead); Unga bunga time',57,datetime('now'),datetime('now')),
('cced7cb9-fa25-46ad-8835-748da249713b','Juri','Feng Shui Engine (dash)','','214214P (hold)','super',9,11,26,-17,-4,300,'H','','Armor Break; Dash is cancelable on Hit or Block into normals (FSE chain version of the normals); Puts airborne opponents into a juggle state (free juggle state if it''s the first hit, otherwise just maintains the same juggle state as it was)',58,datetime('now'),datetime('now')),
('9900a50c-eca4-42d7-8312-36b825947b36','Juri','Kaisen Dankai Raku','','214214K','super',10,4,52,-36,NULL,4000,'H','','Fully invincible on frames 1-13; Armor Break; Depletes 1.5 Drive Bars on hit for the opponent; Super cinematic time regenerates ~2 Drive Bars for Juri; Incurs 10% damage scaling when canceled into from specials',59,datetime('now'),datetime('now')),
('fcc5f4b7-f954-4f62-9131-41bdc1148fa2','Juri','Kaisen Dankai Raku (Critical Art)','','214214K (CA)','super',10,4,52,-36,NULL,4500,'H','','Fully invincible on frames 1-13; Critical Art deals +500 extra over regular version (but -2 KDA); Armor Break; Depletes 2 Drive Bars on hit for the opponent; Super cinematic time regenerates ~2.4 Drive Bars for Juri; Incurs 10% damage scaling when canceled into from specials; Capcom knows what the Juri fans want',60,datetime('now'),datetime('now')),
('b6e59d78-436e-4c6e-8c62-0346363fb3a0','Juri','Stand LP [Super Install]','','5LP','normal',4,4,7,-2,5,100,'H','ch, sp, su','Chains into stand LP / crouch LP / crouch LK; A lot of active frames for a jab makes this a good oki tool, can be up to +8/+1 meaty; Incurs 20% damage scaling penalty if used as the first hit of a combo; Damage (100) listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the normal damage (300) when not chained into; Puts airborne opponents into a juggle state when chained into',61,datetime('now'),datetime('now')),
('48cdff19-1f5b-4ee1-ac53-8bf85bc81b47','Juri','Stand MP [Super Install]','','5MP','normal',6,4,12,2,7,400,'H','sp, su','Extremely strong combo / pressure / oki tool with strong + frames and 4 active frames meaning it can be up to +10/+5 when used as a meaty; Hit confirmable into the b+HP Target Combo follow-up; Damage (400) listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the normal damage (600) when not chained into; Puts airborne opponents into a juggle state when chained into',62,datetime('now'),datetime('now')),
('932ff892-d0fd-4bb4-9e56-e783d6efd818','Juri','Stand HP [Super Install]','','5HP','normal',10,3,24,-5,NULL,600,'H','sp, su','Forces stand; Solid whiff punish tool; Knocks down opponent on hit into a juggle state (KD +29) when chained into during Feng Shui Engine (Super Art Level 2); Framedata / damage / properties listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the framedata / damage / properties when not chained into',63,datetime('now'),datetime('now')),
('b9790858-d638-4aed-bd34-fc069c51c19a','Juri','Stand LK [Super Install]','','5LK','normal',5,3,9,-3,2,100,'H','sp, su','Great range for a light and has a full conversion from max range during Feng Shui Engine (Super Art Level 2); Incurs 20% damage scaling penalty if used as the first hit of a combo; Damage (100) listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the normal damage (300) when not chained into; Puts airborne opponents into a juggle state when chained into',64,datetime('now'),datetime('now')),
('5027f911-d659-454c-bf70-4028e3b819d3','Juri','Stand MK [Super Install]','','5MK','normal',5,2,17,-4,3,300,'H','sp, su','Very strong poke tool as well as first hit coming out in only 5F comboing from stLP; Very good when used in combination with Drive Rush; Both hits are cancelable dusing FSE; First hit has 4F less hitstun than normal when chained into during FSE (cannot combo into HK Fuhajin launcher as normal); Damage (300*200) listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the normal damage (400*300) when not chained into; Puts airborne opponents into a juggle state when chained into',65,datetime('now'),datetime('now')),
('88dedf6f-7261-4599-b61c-fa00df2a2b45','Juri','Stand HK [Super Install]','','5HK','normal',17,4,19,-3,NULL,700,'H','sp, su','Really far range attack that''s safe on block and launches the opponent on Punish Counter (KD +45) makes this a very strong poke and footsie tool; The brief extended leg hurtbox on frame 16 of start-up (1F before active) is strike invincible (cannot counter-poke projectiles); Becomes fully cancelable while in Feng Shui Engine (Super Art Level 2); Knocks down opponent on hit into a juggle state (KD +34) when chained into during Feng Shui Engine (Super Art Level 2); Incurs a 20% damage scaling penalty if used as the first hit of a combo; Framedata / damage / properties listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the framedata / damage / properties when not chained into',66,datetime('now'),datetime('now')),
('9a126e63-e1d4-47f4-a22f-14554900c557','Juri','Crouch LP [Super Install]','','2LP','normal',4,3,8,-1,4,100,'H','ch, sp, su','Chains into stand LP / crouch LP / crouch LK; Incurs 20% damage scaling penalty if used as the first hit of a combo; Damage (100) listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the normal damage (300) when not chained into; Puts airborne opponents into a juggle state when chained into',67,datetime('now'),datetime('now')),
('ac2b7ac9-69a2-4af1-a4d7-87e9f15aec82','Juri','Crouch MP [Super Install]','','2MP','normal',6,4,14,-2,5,400,'H','sp, su','Damage (400) listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the normal damage (600) when not chained into; Puts airborne opponents into a juggle state when chained into; +1 extra recovery frame (15F) on whiff only',68,datetime('now'),datetime('now')),
('efcdb50a-cfae-4e1d-affe-90efa91e71ef','Juri','Crouch HP [Super Install]','','2HP','normal',8,4,23,-11,NULL,700,'H','j, sp, su','Extended leg is invincible on airborne strikes on frames 8-15; Forces stand; Solid anti-air; Cannot hit cross-up (behind Juri); Launches opponent on hit into a juggle state (KD +34) when chained into and becomes jump cancelable on Hit while in Feng Shui Engine (Super Art Level 2); All of Juri''s air normals cause a juggle state after jump canceling from crouch HP during Feng Shui Engine (Super Art Level 2); Framedata / damage / properties listed here only refers to when chaining into this move via Feng Shui Engine (Super Art Level 2) - Refer to the regular Juri framedata sheet for the framedata / damage / properties when not chained into',69,datetime('now'),datetime('now')),
