INSERT INTO frame_data (id,character,move_name,move_name_jp,input,category,startup,active,recovery,on_block,on_hit,damage,guard,cancel_into,notes,sort_order,updated_at,created_at) VALUES
('5ead1b15-869c-4a84-b60c-b92e7182935e','Ken','Triple Flash Kicks 2','','5MK > 5MK > 5HK','normal',13,3,28,-11,NULL,700,'H','','Last hit whiffs on crouching if the first hits are blocked making it more punishable (-32); Good range and hit confirmable makes this a good poke / punish tool in neutral; Not a true blockstring on the last hit (2F gap) which is +30 KD the HK hits by itself',22,datetime('now'),datetime('now')),
('955b3eaa-3130-45bd-90bf-d3c6a05da291','Ken','Knee Strikes','','LPLK','throw',5,3,23,NULL,NULL,1200,'T','','Throw Loop: Walk forward into manually timed mixup between throw/strike (not possible on mid-screen back-roll); Throw loop requires 1F timing on standard characters (2F on Marisa, 3F on Blanka/Honda, 4F on Zangief); Gets +70% damage increase (2040 damage), HKD (denies back-roll option on wake-up), and depletes 1 bar of Drive Gauge on a Punish Counter',23,datetime('now'),datetime('now')),
('90d81e34-f7d3-4ad9-b8c2-5c70154944c3','Ken','Hell Wheel','','4LPLK','throw',5,3,23,NULL,NULL,1200,'T','','Back Throw oki: Nope (only +6 at mid-range); Throws the opponent after 50% screen length into the other direction; Gets +70% damage increase (2040 damage), HKD (denies back-roll option on wake-up), and depletes 1 bar of Drive Gauge on a Punish Counter',24,datetime('now'),datetime('now')),
('5dfa1e55-1a12-41a9-82b5-44b26f5ee4ec','Ken','Drive Impact: Flame Strike','','HPHK','unique',26,2,35,-3,NULL,800,'H','','2 hits of armor on frames 1-27; Damages opponents Drive Gauge on Block (1/2 bar) | Hit (1 bar) | Counter-Hit (1.25 bar) | Punish Counter (1.5 bar); Knocks down on hit; Crumples on Punish Counter or after absorbing at least 1 attack during start-up (+21 frames before the crumple state goes airborne, followed by airborne state on frames 22-46 before they are grounded) which counts as 2 hits of damage scaling; If the armor absorbs an attack it slows the overall start-up by 1F (27F total instead of 26F); Pushes the opponent far back on hit or block and causes a wall splat if they hit the wall; Wall Splat on block adds 20% damage penalty on the next hit; Wall splats on hit or during Burnout counts as 2 hits of damage scaling; Wall Splat puts opponent into a special juggle state where the next move juggles them even if it doesn''t normally (similar juggle rules as from Drive Rush); Does not cause wall splat if combo''d into from other moves or unblockable setups (Lock); Puts airborne opponents into a long spinning free juggle state when hit as a Punish Counter; Regular KDA without a Wall Splat: +35 KD; Corner wall splat on HIT: +65 KD | Block: +72 HKD; KDA can vary greatly depending on how high the opponent wall splats (higher KDA the higher they wall splat); Can clash with other Drive Impacts if they collide on the same active frame (start at exactly the same time); Costs 1 bar of Drive Gauge; The scrub killer',25,datetime('now'),datetime('now')),
('55cf8bb9-d7d1-4e31-99bf-2bcf88d475d3','Ken','Drive Reversal: Lightning Crack','','6HPHK','unique',20,3,26,-6,NULL,500,'H','','Fully invincible on frames 1-22 (frames 1-20 when used on wake-up as a Reversal); Armor Break (blows through all armor like Drive Impact); Can be performed during blockstun or from a successful parry (trying to Drive Reversal after the blockstun is over will result in a Drive Impact); Can also be performed during wake-up as a Reversal, doing it this way speeds up the start-up frames by 2 frames (18F start-up instead of 20F); Drive Reversal immediately removes the current blockstun you''re in and starts the attack; Causes a 4F screen freeze that occurs after the 6th start-up frame, which can mess up the opponents input timing, or enable them to do a simple input OS to counter the Drive Reversal; Safe on block (-2) when used against an opponent currently in Burnout; Costs 2 bars of Drive Gauge',26,datetime('now'),datetime('now')),
('620d83cc-6a6f-439d-9d2a-df353849e2c7','Ken','Drive Parry','','MPMK','unique',1,12,33,NULL,NULL,NULL,'','','Parries all strikes and projectiles (high and low) from frame 1; 12F parry window (can hold the parry to extend the parry window); Perfect Parry occurs on the first 2 active frames (cannot achieve Perfect Parry if you buffer into parry by holding it during Reversal windows; Perfect Parries have to be timed properly); Can still hold charge directions during Parry; Can block during the recovery frames of a regular parry (can still get hit during the recovery frames if you don''t block correctly); Getting thrown or hit at any point during the recovery frames of a whiffed parry attempt results in a Punish Counter; Successfully parrying a move puts you into the same amount of blockstun as that move would regularly do on block (but a Perfect Parry has only 1F of recovery); Throw invincible during the recovery of a successful parry (just like during blockstun); Perfect Parrying a strike has only 1F of recovery and disables the opponent from canceling their attack (basically a guaranteed punish opportunity); After a successful Perfect Parry, you suffer a 50% penalty to your Damage, Drive Gauge Generation, and Drive Gauge Damage on any of your following attacks when punishing the opponent (in addition, both you and the opponent suffer a 20% penalty to their Super Meter gain during this period); Fully invincible for 6F after a successful Perfect Parry against a strike, during which period you can cancel into anything you want and it carries over the brief invincibility frames; Perfect Parrying projectiles puts you into fixed 10 frames of recovery and applies the same 50% scaling penalties (and 20% Super Meter penalty) on your following attacks when punishing the opponent; Parrying a Strike and Projectile on the same frame will result in a regular parry for the strike attack (effectively ignoring the projectile''s hitstop / blockstun); Perfect Parrying a Strike and Projectile on the same frame will give a screen freeze like you Perfect Parried a Strike, but still give you 10F recovery as if you had Perfect Parried a Projectile; Can cancel into Drive Rush during active frames 3 and onward (fastest Drive Rush method is to buffer a forward input before doing parry + forward again); Can cancel into Drive Reversal from a successful parry (just like you can normally during blockstun); Costs 1/2 bar Drive Gauge (continues to deplete Drive Gauge as you hold the Parry); You lose the parry if you go into Burnout from the Drive Gauge cost; Rewards 1 bar Drive Gauge (1/2 bar total after factoring in the initial parry cost) for successfully parrying a strike; Rewards 1/2 bar of Drive Gauge (0 bar total after factoring in the initial parry cost) for successfully parrying a projectile; Rewards 2 bars of Drive Gauge (1.5 bars total after factoring in the initial parry cost) for successful parrying a Drive Impact; Successfully parrying a strike attack splits the regular block pushback between both players (while Perfect Parrying a strike removes all of its pushback); Successfully parrying a projectile or Drive Impact reduces the pushback of it by half (while Perfect Parrying a projectile or Drive Impact removes all of its pushback); Your hurtbox and throw box expand slightly towards the opponent for the entire duration of the Parry (Throw box extension starts instantly on frame 1, while the Hurtbox extension starts on frame 3, after the initial 2F Perfect Parry window); Parrying while crouching maintains a regular crouch hurtbox for the first 2 frames of the parry (during the initial Perfect Parry window)',27,datetime('now'),datetime('now')),
('9161e0d9-3468-4bfc-90f4-4b64cf440396','Ken','Drive Rush','','MPMK / 66 (cancel)','unique',9,38,24,NULL,NULL,NULL,'','','Dashes forward and enhances the next normal used out of the Drive Rush with +4 extra hitstun / blockstun (some moves also get unique properties enhanced such as juggle state); The +4 bonus frame advantage gained from a Drive Rush enhanced move also stacks with any bonus frame advantage that move may have gained from Counter-Hit or Punish Counter; Cancelable into from special cancelable grounded normals; Drive Rush maintains buffers (freezes the buffer window) during it start-up and freeze frames - This allows players to do things normally not possible within the normal buffer windows, such as Drive Rushing into a charge special; The initial freeze frames that occur when a Drive Rush happens eats the opponents inputs; Framedata shown in parentheses refers to the Drive Rush version used from a Parry; Drive Rush recovery frames is only 24F total (23F if done from a Parry) - but the enhanced dash itself is 46F total (45F if done from Parry) and you can cancel it as early as frame 9 (frame 11 if done from a Parry); You stop building any form of Drive Gauge on your attacks after using a Drive Rush in the MIDDLE of a combo (but you still continue to build drive gauge as normal if you did Drive Rush at the START of a combo); Applies extra damage scaling penalty after using a Drive Rush in the MIDDLE of a combo (no damage scaling if you use Drive Rush at the START of a combo); Costs 3 bars of Drive Gauge if canceled into from a move; Costs 1/2 bar of Drive Gauge if canceled into from Parry (for a total of 1 bar of Drive Gauge when you factor in the initial 1/2 bar cost of the Parry)',28,datetime('now'),datetime('now')),
