('5b43b5ea-e94b-43ea-9179-bc0365995608','Kimberly','Stand LP [Super Install]','','5LP','normal',5,2,8,-2,5,299,'H','ch, sp, su, tc','Chains into stand LP / crouch LP / crouch LK; Has several Target Combo follow-ups via the classic Bushin Chain; Incurs 20% damage scaling penalty if used as the first hit of a combo',80,datetime('now'),datetime('now')),
