('1106fec0-d923-4ada-bec7-6e8412c593f3','Kimberly','Bushin Prism Strikes 3 [Super Install]','','5LP > 5MP > 5HP > 5HK ','normal',26,3,19,-12,NULL,571,'H','','Last hit (HK) spikes down opponent into a short OTG bounce state; 10F gap on block before the final HK; Grants enough knockdown advantage for a Spraycan setup in the corner',104,datetime('now'),datetime('now')),
('80e8bf2c-d645-4736-872c-b0466eef2827','Kimberly','Bushin Hellchain 1 [Super Install]','','5LP > 5MP > 2HP','normal',10,2,25,-10,2,637,'H','','Keeps the opponent grounded and leaves Kimberly up close and +2 on Hit (can be good to maintain grounded pressure / mixups); Can be a good tool against Drive Impact since the third hit will break armor and be +4 on Counter-Hit for a full combo conversion',105,datetime('now'),datetime('now')),
