('b2641ba0-87c9-4b64-b864-d30628321ba2','Kimberly','Arc Step > Bushin Hojin Kick [Super Install]','','236K (proximity) > K','special',8,6,20,-8,NULL,1197,'H','','Not an Overhead; Forced Knockdown state while airborne; +1 extra KDA (KD +31) if the opponent blocks the first hit (Arc Step); -1 less KDA (KD +29) when hitting a cornered opponent',127,datetime('now'),datetime('now')),
