('848280e9-500a-43bb-a56d-90889b08a42c','Kimberly','Bushin Ninjastar Cypher (Critical Art) [Super Install]','','236236P (CA)','super',8,6,44,-35,NULL,4500,'H','','Fully invincible on frames 1-13; Grants Kimberly +11% walk speed and damage bonus for the rest of the match; Critical Art does +500 extra damage over regular version; Armor Break; Depletes 2 Drive Bars on hit for the opponent; Super cinematic time regenerates ~2.1 Drive Bars for Kimberly; Incurs a 10% damage scaling when canceled into from specials',144,datetime('now'),datetime('now')),
('63d93b25-2bcd-4428-9055-34a23eca4519','Lily','Stand LP','','5LP','normal',5,3,8,-1,6,350,'H','ch, sp, su','Chains into stand LP / crouch LP / stand LK / crouch LK; Deals 50 extra damage over Lily''s other light attacks; Incurs 20% damage scaling penalty if used as the first hit of a combo',1,datetime('now'),datetime('now')),
