('def5a317-f2a9-4a94-8588-313972fb8144','Manon','Révérence','','4HP','normal',8,6,17,1,3,800,'H','sp, su','Manon''s main combo tool; Very strong tool for pressure and oki; Puts airborne opponents into a limited juggle state',19,datetime('now'),datetime('now'));
INSERT INTO frame_data (id,character,move_name,move_name_jp,input,category,startup,active,recovery,on_block,on_hit,damage,guard,cancel_into,notes,sort_order,updated_at,created_at) VALUES
('cbb0eb1c-bd83-431e-9636-062e7a8b8deb','Manon','Tomoe Derrière','','3HK','normal',11,9,32,-23,NULL,1000,'H','','Not a low attack (despite looking like a slide); Manon''s kicking leg is invincible to airborne strikes on frames 9-19; Strong vertical anti-air and juggle tool; Can hit cross-up (behind Manon); Manon kicks airborne opponents back over her to the other side (air reset); Knocks down grounded opponents on hit; Punish Counter: Manon kicks the opponent back over her and scores a Hard Knockdown (HKD) for follow-up oki; Only first active frame hits grounded opponents (mostly used against airborne opponents)',20,datetime('now'),datetime('now')),
('8568aec0-7f55-4b98-9735-5be8d4001d51','Manon','Back MK','','4MK','normal',10,4,19,-3,-1,600,'H','tc','Fantastic anti-air tool against horizontal and vertical approaches (but cannot hit cross-up behind Manon); Puts airborne opponents into a limited juggle state; Cancelable into an Overhead target combo follow-up (MK) on frames 17-25 (does not combo naturally if the cancel is delayed at all)',21,datetime('now'),datetime('now')),
('4c0a9cb5-4025-4d43-9f96-3fc0b73e10b5','Manon','En Haut','','4MK > 5MK','normal',14,5,21,-11,-3,500,'M','sp, su','Overhead string that''s also fully cancelable (very rare in Street Fighter); Forces crouch on hit; Puts airborne opponents into a limited OTG juggle state; Combos naturally if this Overhead follow-up is not delayed at all; 2F gap on block that can be made bigger by manually delaying this overhead follow-up (various frametrap scenarios)',22,datetime('now'),datetime('now')),
('10fbc269-281e-4b19-b564-e53ecfe69a23','Manon','À Terre','','5MP > 5MK','normal',10,2,17,-5,2,500,'H','','Pulls the opponent up close to Manon for a +2 mixup situation on hit; The initial stand MP can be canceled into this MK follow-up on frames 12-14 (15F hit confirm window if you factor in the 12F hitstop of stand MP); Grants a Hard Knockdown (+32) after Punish Counter stand MP that grants strong oki anywhere on the screen',23,datetime('now'),datetime('now')),
('994dc422-2cb5-433f-8bea-34e8050c5f4a','Manon','Temps Lié','','5HP > 5HP','normal',5,2,20,-8,3,600,'H','','+2F extra recovery frames (22F) on block only; Pulls the opponent up close to Manon for a +3 mixup situation on hit (much easier to hit confirm this one than the MP>MK target combo); First HP hit puts airborne opponents into a limited juggle state on hit (then the HP follow-up pulls the opponent in with an air reset); The initial stand HP can be canceled into this HP follow-up on frames 18-25 (28F hit confirm window if you factor in the 13F hitstop of stand HP); Puts opponent into a limited juggle state when landed after Punish Counter stand HP (KD +48); This juggled hit counts as 2 hits for damage scaling',24,datetime('now'),datetime('now')),
('8a07d7a0-dec2-48f9-ab00-506491e34ef9','Manon','Allongé','','2HP > 5HP','normal',4,4,26,-10,5,500,'H','','Spikes down airborne opponents into a +17~19 Knockdown state (higher KDA the higher in the air the opponent is when pulled down)',25,datetime('now'),datetime('now')),
('a8a784fe-50ef-4933-8d11-bdbf98b3d0e0','Manon','Ouchi Gari','','LPLK','throw',5,3,23,NULL,NULL,1200,'T','','Throw Loop: Manually time throw on their wake-up (not possible on mid-screen back-roll); Gets +70% damage increase (2040 damage), HKD (denies back-roll option on wake-up), and depletes 1 bar of Drive Gauge on a Punish Counter',26,datetime('now'),datetime('now')),
('4d4fb9f0-8185-4876-94b6-11b75f97e5ad','Manon','Uchi Mata','','4LPLK','throw',5,3,23,NULL,NULL,1200,'T','','Basic meaties but no meaty throw (unless this connects when Manon is cornered); Gets +70% damage increase (2040 damage), HKD (denies back-roll option on wake-up), and depletes 1 bar of Drive Gauge on a Punish Counter',27,datetime('now'),datetime('now')),
('1b0d4311-a68f-4782-a4be-aa8ee6c8abb5','Manon','Drive Impact: Glissade','','HPHK','unique',26,2,35,-3,NULL,800,'H','','2 hits of armor on frames 1-27; Damages opponents Drive Gauge on Block (1/2 bar) | Hit (1 bar) | Counter-Hit (1.25 bar) | Punish Counter (1.5 bar); Knocks down on hit; Crumples on Punish Counter or after absorbing at least 1 attack during start-up (+21 frames before the crumple state goes airborne, followed by airborne state on frames 22-46 before they are grounded) which counts as 2 hits of damage scaling; If the armor absorbs an attack it slows the overall start-up by 1F (27F total instead of 26F); Pushes the opponent far back on hit or block and causes a wall splat if they hit the wall; Wall Splat on block adds 20% damage penalty on the next hit; Wall splats on hit or during Burnout counts as 2 hits of damage scaling; Wall Splat puts opponent into a special juggle state where the next move juggles them even if it doesn''t normally (similar juggle rules as from Drive Rush); Does not cause wall splat if combo''d into from other moves or unblockable setups (Lock); Puts airborne opponents into a long spinning free juggle state when hit as a Punish Counter; Regular KDA without a Wall Splat: +35 KD; Corner wall splat on HIT: +65 KD | Block: +72 HKD; KDA can vary greatly depending on how high the opponent wall splats (higher KDA the higher they wall splat); Can clash with other Drive Impacts if they collide on the same active frame (start at exactly the same time); Costs 1 bar of Drive Gauge; The scrub killer',28,datetime('now'),datetime('now')),
('27de550f-ca5a-4b67-93dc-9b6891004213','Manon','Drive Reversal: Écarté','','6HPHK','unique',20,3,26,-6,NULL,500,'H','','Fully invincible on frames 1-22 (frames 1-20 when used on wake-up as a Reversal); Armor Break (blows through all armor like Drive Impact); Can be performed during blockstun or from a successful parry (trying to Drive Reversal after the blockstun is over will result in a Drive Impact); Can also be performed during wake-up as a Reversal, doing it this way speeds up the start-up frames by 2 frames (18F start-up instead of 20F); Drive Reversal immediately removes the current blockstun you''re in and starts the attack; Causes a 4F screen freeze that occurs after the 6th start-up frame, which can mess up the opponents input timing, or enable them to do a simple input OS to counter the Drive Reversal; Safe on block (-2) when used against an opponent currently in Burnout; Costs 2 bars of Drive Gauge',29,datetime('now'),datetime('now')),
('95dfc51e-73d2-44a7-ad7b-048d7d451495','Manon','Drive Parry','','MPMK','unique',1,12,33,NULL,NULL,NULL,'','','Parries all strikes and projectiles (high and low) from frame 1; 12F parry window (can hold the parry to extend the parry window); Perfect Parry occurs on the first 2 active frames (cannot achieve Perfect Parry if you buffer into parry by holding it during Reversal windows; Perfect Parries have to be timed properly); Can still hold charge directions during Parry; Can block during the recovery frames of a regular parry (can still get hit during the recovery frames if you don''t block correctly); Getting thrown or hit at any point during the recovery frames of a whiffed parry attempt results in a Punish Counter; Successfully parrying a move puts you into the same amount of blockstun as that move would regularly do on block (but a Perfect Parry has only 1F of recovery); Throw invincible during the recovery of a successful parry (just like during blockstun); Perfect Parrying a strike has only 1F of recovery and disables the opponent from canceling their attack (basically a guaranteed punish opportunity); After a successful Perfect Parry, you suffer a 50% penalty to your Damage, Drive Gauge Generation, and Drive Gauge Damage on any of your following attacks when punishing the opponent (in addition, both you and the opponent suffer a 20% penalty to their Super Meter gain during this period); Fully invincible for 6F after a successful Perfect Parry against a strike, during which period you can cancel into anything you want and it carries over the brief invincibility frames; Perfect Parrying projectiles puts you into fixed 10 frames of recovery and applies the same 50% scaling penalties (and 20% Super Meter penalty) on your following attacks when punishing the opponent; Parrying a Strike and Projectile on the same frame will result in a regular parry for the strike attack (effectively ignoring the projectile''s hitstop / blockstun); Perfect Parrying a Strike and Projectile on the same frame will give a screen freeze like you Perfect Parried a Strike, but still give you 10F recovery as if you had Perfect Parried a Projectile; Can cancel into Drive Rush during active frames 3 and onward (fastest Drive Rush method is to buffer a forward input before doing parry + forward again); Can cancel into Drive Reversal from a successful parry (just like you can normally during blockstun); Costs 1/2 bar Drive Gauge (continues to deplete Drive Gauge as you hold the Parry); You lose the parry if you go into Burnout from the Drive Gauge cost; Rewards 1 bar Drive Gauge (1/2 bar total after factoring in the initial parry cost) for successfully parrying a strike; Rewards 1/2 bar of Drive Gauge (0 bar total after factoring in the initial parry cost) for successfully parrying a projectile; Rewards 2 bars of Drive Gauge (1.5 bars total after factoring in the initial parry cost) for successful parrying a Drive Impact; Successfully parrying a strike attack splits the regular block pushback between both players (while Perfect Parrying a strike removes all of its pushback); Successfully parrying a projectile or Drive Impact reduces the pushback of it by half (while Perfect Parrying a projectile or Drive Impact removes all of its pushback); Your hurtbox and throw box expand slightly towards the opponent for the entire duration of the Parry (Throw box extension starts instantly on frame 1, while the Hurtbox extension starts on frame 3, after the initial 2F Perfect Parry window); Parrying while crouching maintains a regular crouch hurtbox for the first 2 frames of the parry (during the initial Perfect Parry window)',30,datetime('now'),datetime('now')),
('6d28d922-736c-4ebc-b114-9fbca923a9b3','Manon','Drive Rush','','MPMK / 66 (cancel)','unique',9,45,24,NULL,NULL,NULL,'','','Dashes forward and enhances the next normal used out of the Drive Rush with +4 extra hitstun / blockstun (some moves also get unique properties enhanced such as juggle state); The +4 bonus frame advantage gained from a Drive Rush enhanced move also stacks with any bonus frame advantage that move may have gained from Counter-Hit or Punish Counter; Cancelable into from special cancelable grounded normals; Drive Rush maintains buffers (freezes the buffer window) during it start-up and freeze frames - This allows players to do things normally not possible within the normal buffer windows, such as Drive Rushing into a charge special; The initial freeze frames that occur when a Drive Rush happens eats the opponents inputs; Framedata shown in parentheses refers to the Drive Rush version used from a Parry; Drive Rush recovery frames is only 24F total (23F if done from a Parry) - but the enhanced dash itself is 46F total (45F if done from Parry) and you can cancel it as early as frame 9 (frame 11 if done from a Parry); You stop building any form of Drive Gauge on your attacks after using a Drive Rush in the MIDDLE of a combo (but you still continue to build drive gauge as normal if you did Drive Rush at the START of a combo); Applies extra damage scaling penalty after using a Drive Rush in the MIDDLE of a combo (no damage scaling if you use Drive Rush at the START of a combo); Costs 3 bars of Drive Gauge if canceled into from a move; Costs 1/2 bar of Drive Gauge if canceled into from Parry (for a total of 1 bar of Drive Gauge when you factor in the initial 1/2 bar cost of the Parry)',31,datetime('now'),datetime('now')),
('0b1e0b1d-6691-4a3d-88e7-c75909257e88','Manon','Taunt','','5PPPKKK','unique',NULL,NULL,NULL,NULL,NULL,NULL,'','','',32,datetime('now'),datetime('now')),
