('ab0ee7e9-f0f0-49f4-9067-9f595dbbc6c8','Marisa','Stand HP (hold)','','5HP (hold)','normal',23,2,21,4,7,1200,'H','tc','Uncharged version comes out in only 5 frames if HP is released between start-up frames 7-17; Great range and frame advantage on hit and block makes this a great combo / pressure / bully tool; +1 extra recovery frame (22F) on whiff; Incurs 10% damage scaling penalty if used as the first hit of a combo',4,datetime('now'),datetime('now')),
('35368d8a-723e-488c-93ab-ffd3eafab72e','Marisa','Stand LK','','5LK','normal',6,2,14,-2,0,400,'H','sp, su','Does not combo into anything at farther ranges except Super Art 2; Incurs 20% damage scaling penalty if used as the first hit of a combo',5,datetime('now'),datetime('now')),
