('eb639bf8-ceab-4f4a-9955-69aeb44e1b6d','Marisa','Novacula','','6MP','normal',10,2,20,-3,2,800,'H','tc','Forward moving attack with high/low follow-up options; Great range for a 10F move makes this a great punish tool in some matchups; Can combo after on Counter-Hit or Punish Counter',28,datetime('now'),datetime('now')),
